let tenant = null;
try { tenant = (($vars.SEO_TENANT || 'operand')); } catch (e) { tenant = null; }
tenant = (tenant === null || tenant === undefined || String(tenant).trim() === '') ? null : String(tenant).trim();
const DAY = 86400000;
const now = Date.now();
// UTC day-aligned trailing 7-day window ending at the start of today.
const endMs = new Date(new Date(now).setUTCHours(0, 0, 0, 0)).getTime();
const startMs = endMs - 7 * DAY;
const iso = (ms) => new Date(ms).toISOString();
return [{ json: {
  __tenant: tenant,
  __period_start: iso(startMs),
  __period_end: iso(endMs),
} }];

