const ctx = $('Capture Run').all();
const items = $input.all();
const out = [];
const TOP_N = 5;
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const c = (ctx[i] || ctx[0] || { json: {} }).json;
  const status = Number(resp.statusCode || 0);
  let rows = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return []; try { return JSON.parse(__s); } catch (__e) { return []; } })(resp.body);
  if (!Array.isArray(rows)) rows = rows ? [rows] : [];
  const queueOk = !(status && (status < 200 || status >= 300));
  const run = c.__latest_run || null;
  let factsOk = false;
  let reason = null;
  let topTasks = [];
  let __total_open = 0;
  if (!c.__run_ok || !run) { reason = 'no_audit_run'; }
  else if (!queueOk) { reason = 'queue_error_' + (status || 'unknown'); }
  else {
    // Only real open queue rows contribute — no invented tasks. Ordered priority_score desc
    // (stable by task_id) from the read. total_open counts the WHOLE bounded scan (the real
    // backlog); top_tasks surfaces only the top-N in prose → honest "N of M" reporting.
    let totalOpen = 0;
    for (const r of rows) {
      if (!r || r.task_id == null) continue;
      totalOpen++;
      if (topTasks.length < TOP_N) {
        topTasks.push({
          task_id: String(r.task_id),
          url_or_entity: r.url_or_entity == null ? null : String(r.url_or_entity),
          issue_classes: Array.isArray(r.issue_classes) ? r.issue_classes : [],
          severity: r.severity == null ? null : String(r.severity),
          priority_score: Number.isFinite(Number(r.priority_score)) ? Number(r.priority_score) : null,
          recommendation: r.recommendation == null ? null : String(r.recommendation),
        });
      }
    }
    __total_open = totalOpen;
    factsOk = totalOpen > 0;
    if (!factsOk) reason = 'no_open_tasks';
  }
  // Honesty flag: the latest run may predate the reporting window (no fresh audit this period).
  // We still report it (the freshest available) but SAY it is older — never present stale data
  // as current. Compared as YYYY-MM-DD day strings (run_date is a date; window start is a ts).
  const winStartDay = c.__period_start ? String(c.__period_start).slice(0, 10) : null;
  const runDay = (run && run.run_date != null) ? String(run.run_date).slice(0, 10) : null;
  const staleRun = !!(runDay && winStartDay && runDay < winStartDay);
  const sourceFacts = {
    run: run ? {
      run_date: run.run_date != null ? String(run.run_date) : null,
      status: run.status != null ? String(run.status) : null,
      child_status: (run.child_status && typeof run.child_status === 'object') ? run.child_status : {},
      summary: run.summary != null ? String(run.summary) : null,
    } : null,
    top_tasks: topTasks,
    task_count: topTasks.length,
    total_open: __total_open,
    stale_run: staleRun,
    window: { start: c.__period_start, end: c.__period_end },
  };
  out.push({ json: Object.assign({}, c, {
    __facts_ok: factsOk,
    __facts_reason: reason,
    __source_facts: sourceFacts,
  }) });
}
return out;

const ctx = $('Extract Facts').all().filter((it) => it.json && it.json.__facts_ok === true);
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const c = (ctx[i] || ctx[0] || { json: {} }).json;
  let p = items[i].json || {};
  if (p.body && typeof p.body === 'object') p = p.body; // envelope tolerance
  let summary = null;
  const cand = (p && typeof p === 'object') ? (p.summary || p.executive_summary || p.reply_draft || p.rationale) : null;
  if (typeof cand === 'string' && cand.trim()) summary = cand.trim().slice(0, 1200);
  out.push({ json: Object.assign({}, c, { __summary: summary }) });
}
return out;

const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  const facts = j.__source_facts || {};
  const win = facts.window || {};
  const day = (iso) => (iso ? String(iso).slice(0, 10) : '?');
  const header = 'SEO report — ' + day(win.start) + ' to ' + day(win.end);
  let body;
  let status;
  if (j.__facts_ok === true) {
    status = 'sent';
    const run = facts.run || {};
    const cs = (run.child_status && typeof run.child_status === 'object') ? run.child_status : {};
    const csLine = Object.keys(cs).map((k) => k + ':' + cs[k]).join(', ');
    const totalOpen = (facts.total_open != null) ? facts.total_open : facts.task_count;
    const shown = Array.isArray(facts.top_tasks) ? facts.top_tasks.length : 0;
    // Honest "showing N of M" so top-N never understates the real backlog.
    const stale = facts.stale_run ? ' (no NEW audit this period — showing the most recent, from ' + day(run.run_date) + ')' : '';
    const headline = 'Latest audit (' + day(run.run_date) + '): ' + (run.status || 'unknown') +
      ' — ' + totalOpen + ' prioritized action(s) open' + stale + '.';
    const health = 'Health snapshot — ' + (csLine || 'no child status recorded') + '.';
    const tasks = (Array.isArray(facts.top_tasks) ? facts.top_tasks : []).map((t, i) => {
      const cls = (t.issue_classes || []).join('+');
      const rec = t.recommendation ? (' — ' + String(t.recommendation).slice(0, 160)) : '';
      return (i + 1) + '. [' + (t.priority_score == null ? '?' : t.priority_score) + '] ' +
        (t.url_or_entity || '?') + ' (' + cls + ', ' + (t.severity || 'info') + ')' + rec;
    });
    const topsHeader = 'Top prioritized actions (' + shown + ' of ' + totalOpen + '):';
    body = [header, '', headline, health, '', topsHeader, ...tasks].join('\n');
  } else {
    // HONEST FAILURE: nothing usable from the orchestrator — say so, invent nothing.
    status = (j.__facts_reason && String(j.__facts_reason).indexOf('error') !== -1) ? 'error' : 'no_data';
    const why = j.__facts_reason ? (' (' + j.__facts_reason + ')') : '';
    body = header + '\n\nNo SEO audit results are available to report for this period' + why +
      '. No figures or actions are shown because none were returned from the audit tables.';
  }
  const summary = j.__summary ? (j.__summary + '\n\n') : '';
  const report = summary + body;
  out.push({ json: Object.assign({}, j, { __report: report, __status: status }) });
}
return out;

const crypto = require('crypto');
const readSecret = (k) => {
  let v = null;
  try { v = $env[k]; } catch (e) {}
  if (v === null || v === undefined || v === '') {
    try { v = typeof $vars !== 'undefined' ? $vars[k] : null; } catch (e) {}
  }
  return (v === null || v === undefined) ? '' : String(v);
};
const SECRET = readSecret("N8N_WEBHOOK_SECRET");
const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  const facts = j.__source_facts || {};
  const payload = {
    message: '🧾 ' + String(j.__report || '').slice(0, 3500),
    kind: 'seo_reporting_digest',
    tenant: j.__tenant || null,
    status: j.__status || null,
    period_start: j.__period_start || null,
    period_end: j.__period_end || null,
    task_count: (facts.total_open != null ? facts.total_open : (facts.task_count || 0)),
  };
  const ts = String(Date.now());
  out.push({ json: Object.assign({}, j, {
    __notify_payload: payload,
    __notify_ts: ts,
    __notify_sig: SECRET ? crypto.createHmac('sha256', SECRET).update(ts + '.' + JSON.stringify(payload)).digest('hex') : '',
  }) });
}
return out;

const ctx = $('Compose Report').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const c = (ctx[i] || ctx[0] || { json: {} }).json;
  const status = Number(resp.statusCode || 0);
  const delivered = status >= 200 && status < 300;
  // A no_data / error report still records its run; sent_at is set only when the report was
  // actually delivered AND had data to report.
  const sentAt = (delivered && c.__status === 'sent') ? new Date().toISOString() : null;
  out.push({ json: Object.assign({}, c, { __sent_at: sentAt }) });
}
return out;
